WHERE id='gen-gemini-1780644622-4-5m5wc';

UPDATE questions
SET publish_state='published',
    review_status='final-curated-live',
    rationale='The lithium level is elevated with neurologic and gastrointestinal toxicity signs plus impaired renal clearance. Appropriate actions are to stop lithium, give isotonic IV fluids to support renal elimination, and monitor serial lithium levels.',
    deep_rationale='Lithium has a narrow therapeutic index and is cleared primarily through the kidneys. This client has confusion, tremor, nausea, lithium 2.0 mEq/L, mild hyponatremia, and elevated creatinine, which together suggest toxicity with reduced clearance. The first safety step is to discontinue lithium so the exposure does not continue. Isotonic normal saline supports volume status and renal lithium elimination, especially when sodium depletion or dehydration contributes to lithium retention. Serial lithium levels are needed because tissue redistribution can cause rebound and because treatment decisions depend on trend, symptoms, and renal function. Activated charcoal does not effectively bind lithium because lithium is a small charged metal ion. Direct sodium supplements are not the standard acute treatment; isotonic IV saline addresses volume and sodium physiology more safely. Clinical pearl: lithium toxicity is a renal-clearance problem; stop the drug, hydrate with isotonic saline, monitor levels and neurologic status, and escalate for dialysis when toxicity is severe.',
    references_json='[{"title":"Lithium Toxicity - StatPearls, NCBI Bookshelf","citation":"NCBI Bookshelf describes lithium toxicity management, including that activated charcoal does not effectively adsorb lithium and that hemodialysis is used for severe toxicity or renal failure."},{"title":"Lithium - StatPearls, NCBI Bookshelf","citation":"NCBI Bookshelf describes hydration and discontinuation of lithium as primary management, with normal saline facilitating lithium excretion."},{"title":"NCSBN 2026 NCLEX-RN Test Plan","citation":"NCSBN 2026 RN Test Plan, Pharmacological and Parenteral Therapies and Clinical Judgment."}]',
    deep_rationale_authored_at=unixepoch(),
    provenance=COALESCE(provenance,'gen') || '|editorial-batch-007:manual-source-backed-promote'
WHERE id='gen-nemotron-1780643721-5-uyun1';
